changeSet.sql:
-- Schema usage GRANT USAGE ON SCHEMA nexus TO nexus_svc; GRANT USAGE ON SCHEMA t1 TO nexus_svc;
DO $$ DECLARE rel RECORD; skipped_count integer; skipped_names text; BEGIN -- DML + sequence usage on every relation THIS role owns (nexus_admin -- created the schema, so this covers every table/view/sequence in -- normal operation). Foreign-owned relations (e.g. the superuser-owned -- diag_chash_conformance view) are skipped by construction — nexus_svc -- does not need them. FOR rel IN SELECT n.nspname, c.relname, c.relkind FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace WHERE n.nspname IN ('nexus', 't1') AND c.relkind IN ('r', 'p', 'v', 'm', 'f', 'S') AND pg_get_userbyid(c.relowner) = current_user LOOP IF rel.relkind = 'S' THEN EXECUTE format( 'GRANT USAGE, SELECT ON %I.%I TO nexus_svc', rel.nspname, rel.relname ); ELSE EXECUTE format( 'GRANT SELECT, INSERT, UPDATE, DELETE ON %I.%I TO nexus_svc', rel.nspname, rel.relname ); END IF; END LOOP;
-- Operator visibility (review finding): a foreign-owned relation is -- skipped BY DESIGN — only its owner can grant on it, and nexus_svc does -- not need the diag view today. But a deployment that ever drifts from -- the nexus_admin-owns-everything contract (e.g. a future -- superuser-provisioned object nexus_svc DOES need) would otherwise fail -- silently at first query instead of visibly at boot. NOTICE, not -- WARNING: skip is by design, not an error. SELECT count(*), string_agg(n.nspname || '.' || c.relname, ', ') INTO skipped_count, skipped_names FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace WHERE n.nspname IN ('nexus', 't1') AND c.relkind IN ('r', 'p', 'v', 'm', 'f', 'S') AND pg_get_userbyid(c.relowner) != current_user;
IF skipped_count > 0 THEN RAISE NOTICE 'grants-nexus-svc-1: skipped % foreign-owned relation(s), not granted to nexus_svc (only their owner can grant): %', skipped_count, skipped_names; END IF; END $$;
-- MAINTAIN on chash_alias (rdr180-17 / F2, production 2026-07-20): the rekey and -- staging-promote paths ANALYZE this table INSIDE their own transaction, because a -- multi-tenant store's SECOND tenant onward is otherwise planned against statistics -- autoanalyze froze at "100% tenant 1" while the current tenant's alias rows are still -- uncommitted and invisible. Measured cost of the blindness: 101 minutes versus 461 -- seconds for identical work. -- WHY A GRANT IS REQUIRED, not just the statement: nexus_svc holds DML only and does -- not own the table, and Postgres does NOT error when a non-owner analyzes — it emits a -- WARNING and SKIPS. Without MAINTAIN the ANALYZE is a SILENT no-op that leaves the -- planner exactly as blind. -- MAINTAIN is PostgreSQL 17+, and this changeset runs against substrates whose major -- version nexus does NOT choose: -- * MANAGED/cloud: no PostgreSQL is installed by us at all — the engine runs against -- a provider-managed server (Crunchy Bridge), whose major is theirs, not ours. -- Verified 2026-07-20: major_version 17, live 17.10 (170010) — so the grant DOES -- apply in production and F2's in-transaction ANALYZE is live there. Their major -- can still move without our say, which is why this stays a guard and not an -- assumption. -- * LOCAL service: we always install our own signed bundle (17.5, PG_VERSION in -- engine-service-release.yml) — never a host PostgreSQL, which is not a supported -- mode — BUT the explicit data-directory carve-out deliberately KEEPS the cluster -- an earlier, pre-bundle install created, and those can be older. -- This guard is therefore NOT a bring-your-own fallback and NOT detect-and-adapt about -- our own provisioning; it is a precondition on a statement that would otherwise -- CRASH-LOOP boot on a substrate we did not pick (the GH #1390 shape: never let a -- migration hard-fail a store it cannot fix). Where MAINTAIN is unavailable the -- in-transaction ANALYZE degrades to the no-op described above; the engine reports -- `alias_stats_refreshed` per run so that is auditable rather than assumed, and this -- NOTICE names it at boot rather than leaving it to be discovered as a slow rekey. DO $$ BEGIN IF current_setting('server_version_num')::int >= 170000 THEN EXECUTE 'GRANT MAINTAIN ON nexus.chash_alias TO nexus_svc'; ELSE RAISE NOTICE 'grants-nexus-svc: server % predates MAINTAIN (PG17+); the rekey/promote in-transaction ANALYZE of nexus.chash_alias will be SKIPPED by Postgres. Single-tenant stores are unaffected; a multi-tenant rekey may plan against stale statistics (F2, rekey cascade measured 101min vs 461s).', current_setting('server_version'); END IF; END $$;
-- Default privileges: future tables/sequences created by the schema owner automatically -- carry the same grants for nexus_svc (self-healing for new migrations). ALTER DEFAULT PRIVILEGES IN SCHEMA nexus GRANT SELECT, INSERT, UPDATE, DELETE ON TABLES TO nexus_svc; ALTER DEFAULT PRIVILEGES IN SCHEMA nexus GRANT USAGE, SELECT ON SEQUENCES TO nexus_svc; ALTER DEFAULT PRIVILEGES IN SCHEMA t1 GRANT SELECT, INSERT, UPDATE, DELETE ON TABLES TO nexus_svc; ALTER DEFAULT PRIVILEGES IN SCHEMA t1 GRANT USAGE, SELECT ON SEQUENCES TO nexus_svc;
